// rls/internal/keys/builder.go
package keys

import (
	"encoding/json"
	"fmt"
	"strings"

	"github.com/google/go-cmp/cmp"
	"google.golang.org/grpc/internal/grpcutil"
	"google.golang.org/grpc/metadata"
	"google.golang.org/grpc/serviceconfig"
)

type BuilderMap map[string]*Builder

func (bm BuilderMap) Equal(bm2 BuilderMap) bool {
	return cmp.Equal(bm, bm2, cmp.AllowUnexported(Builder{}, keyBuilder{}))
}

type Builder struct {
	path         string
	keys         []keyBuilder
	constantKeys map[string]string
}

type keyBuilder struct {
	names         []string
	key           string
	requiredMatch bool
}
